      "ruleScoring": {
        "useLexicalPatterns": true,
        "applySubtypeRules": true,
        "boundedAggregation": true,
        "tuningParameters": {
          "KHigh": 1,
          "KMedium": 0.7,
          "KLow": 0.3,
          "M_medium": 0.7,
          "M_low": 0.3,
          "TAIL_DAMPEN": 0.5,
          "TAIL_RATIO_CAP": 0.3,
          "aggregationCap": 1
        }
      },
      "attributeProcessing": {
        "detectSelfSent": true,
        "resolveDomains": true,
        "deriveContextFlags": true
