      "attributeInfluence": {
        "applyBonuses": true,
        "applyPenalties": true,
        "enforceCaps": true,
        "tuningParameters": {
          "bonusMultiplier": 1,
          "penaltyMultiplier": 1,
          "maxTotalBonus": 0.5,
          "maxTotalPenalty": 0.3
        }
      },
      "strongIndicators": {
        "baseWeight": 10,
        "diminishingReturnsFactor": 0.5
      },
      "disambiguation": {
        "pairwiseAdjustments": true,
        "confidenceGapThreshold": 0.13333333333333333
      },
      "multiLabelSelection": {
        "maxLabels": 3,
        "highConfidenceThreshold": 0.8,
        "mediumConfidenceThreshold": 0.5333333333333333,
        "lowConfidenceThreshold": 0.2,
        "secondaryLabelMinGap": 0.13333333333333333,
        "allowedCombinations": [
          {
            "categories": ["financial", "actionable"]
          },
          {
            "categories": ["financial", "household"]
          }
        ],
        "strictCombinationMode": false
      },
      "hardAssertions": {
        "confidenceFloor": 1.0
      },
      "aiRouting": {
        "highConfidenceThreshold": 0.8,
        "aiRequiredThreshold": 0.5,
        "lowConfidenceThreshold": 0.2,
        "skipAiConditions": ["hardAssertion"]
      },
      "performance": {
        "parallelProcessing": true,
        "maxParallelEmails": 10,
        "batchSize": 50,
        "enableCaching": true,
        "cacheTtlSeconds": 3600
      }
    },
