/**
 * Validate configuration parameters
 */
function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
  if (config.maxLabels < 0) {
    throw new Error('Invalid configuration: maxLabels cannot be negative');
  }

  if (config.mediumConfidenceThreshold < 0) {
    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
  }

  if (thresholds.highConfidenceThreshold <= thresholds.mediumConfidenceThreshold) {
    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
  }

  if (thresholds.mediumConfidenceThreshold <= thresholds.lowConfidenceThreshold) {
    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
  }

  if (thresholds.secondaryLabelMinGap < 0) {
    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
  }
}

/**
 * Rank categories by score in descending order, filtering out zero/negative scores
 */
function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
  category: string;
  score: number;
  confidence: number;
  rationale: string;
  selectedSubtypeId?: string | null;
}> {
  return Object.entries(candidateScores)
    .map(([category, scoreData]) => ({
      category,
      score: scoreData.score || 0,
      confidence: scoreData.confidence || 0,
      rationale: scoreData.rationale || '',
      selectedSubtypeId: scoreData.selectedSubtypeId,
    }))
    .filter((item) => item.score > 0)
    .sort((a, b) => {
      // Primary sort by score (descending)
      if (b.score !== a.score) {
        return b.score - a.score;
      }
      // Secondary sort by category name for stable ordering
      return a.category.localeCompare(b.category);
    });
}

/**
 * Select secondary labels within gap threshold and above minimum confidence
 */
function selectSecondaryLabels(
  rankedCategories: Array<{
    category: string;
    score: number;
    confidence: number;
    rationale: string;
    selectedSubtypeId?: string | null;
  }>,
  selectedLabels: SelectedLabel[],
  primaryCandidate: {
    category: string;
    score: number;
    confidence: number;
    rationale: string;
    selectedSubtypeId?: string | null;
  },
  config: MultiLabelConfig,
  thresholds: ConfidenceThresholds
): void {
  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
    return;
  }

  const primaryScore = primaryCandidate.score;

  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
    const candidate = rankedCategories[i];
    const scoreDifference = primaryScore - candidate.score;

    // Check if candidate meets secondary label criteria
    // candidate.confidence is on 0-100 scale, config.mediumConfidenceThreshold is on 0-1 scale
    const normalizedConfidence = candidate.confidence / 100;
    if (
      normalizedConfidence >= config.mediumConfidenceThreshold &&
      scoreDifference <= thresholds.secondaryLabelMinGap
    ) {
      // Check if combination is allowed
      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
        const secondaryLabel: SelectedLabel = {
          category: candidate.category,
          subtype: candidate.selectedSubtypeId || null,
          confidence: candidate.confidence,
          score: candidate.score,
          isPrimary: false,
          labelOrder: selectedLabels.length + 1,
          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.mediumConfidenceThreshold})`,
        };
        selectedLabels.push(secondaryLabel);
      }
    }
  }
}

/**
 * Check if category combination is allowed based on configuration
 */
function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
  if (primaryCategory === candidateCategory) {
    return true;
  }

  // If strict mode is enabled and combinations are specified, only allow explicit combinations
  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
    return config.allowedCombinations.some((combo) => {
      const categories = combo.categories;
      return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
    });
  }

  // If no combinations specified, allow all (default permissive mode)
  if (config.allowedCombinations.length === 0) {
    return true;
  }

  // If combinations are specified but not in strict mode, still check them
  const isExplicitlyAllowed = config.allowedCombinations.some((combo) => {
    const categories = combo.categories;
    return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
  });

  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
  return isExplicitlyAllowed || !config.strictCombinationMode;
}

/**
 * Update category decisions based on selection results
 */
function updateCategoryDecisions(
  candidateScores: Record<string, CategoryScore>,
  selectedLabels: SelectedLabel[],
  thresholds: ConfidenceThresholds
): void {
  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));

  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
    const score = scoreData.score || 0;

    if (selectedCategoryNames.has(categoryCode)) {
      // Selected categories get decision based on confidence
      if (score >= thresholds.highConfidenceThreshold) {
        scoreData.decision = 'selected';
        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidenceThreshold}) - finalized without AI`;
      } else if (score >= thresholds.mediumConfidenceThreshold) {
        scoreData.decision = 'candidate';
        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidenceThreshold}) - may need AI validation`;
      } else {
        scoreData.decision = 'candidate';
        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidenceThreshold}) - needs AI classification`;
      }
    } else {
      // Non-selected categories are rejected
      scoreData.decision = 'rejected';
      if (score < thresholds.lowConfidenceThreshold) {
        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidenceThreshold})`;
      } else {
        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
      }
    }
  }
}

/**
 * Determine if AI classification is needed based on selected labels
 */
function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
  if (selectedLabels.length === 0) {
    return true; // No labels selected - need AI
  }

  // Check if primary label has high confidence (can skip AI)
  // NOTE: confidence is on 0-100 scale, thresholds are on 0-1 scale
  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
  if (primaryLabel && primaryLabel.confidence / 100 >= thresholds.highConfidenceThreshold) {
    return false; // High confidence primary - skip AI
  }

  // Check if any label is below medium confidence (needs AI)
  const hasLowConfidenceLabel = selectedLabels.some(
    (label) => label.confidence / 100 < thresholds.mediumConfidenceThreshold
  );
  if (hasLowConfidenceLabel) {
    return true; // Has low confidence labels - need AI
  }

  // Medium confidence range - labels are acceptable, skip AI
  return false;
}

